var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"좋은 아침입니다, 아카데미 학생 여러분.","JPN":"おはようございます、アカデミー生徒の皆さん。","ENG":"Good morning, Academy students.","TWN":"學院的同學們，大家早安。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다들 아시겠지만, 아카데미는 학생들의 풍부한 경험과 바른 인성 함양을 위해 정기적으로 외부인사 초청회를 열고 있어요.","JPN":"ご存じのとおり、アカデミーは生徒に豊富な経験を提供し、人格者として成長できる道を提示するべく、定期的に招聘講演会を開いています。","ENG":"As you know, our school regularly invites guest speakers to help us broaden our experience and develop good character.","TWN":"大家應該都知道，為了培養學生有豐富的見識，以及好的品格，學院會定期邀請校外人士來分享。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그 중에서도 오늘은 특별한 분을 모시게 됐습니다.","JPN":"そして本日はとても特別な方をお招きしました。","ENG":"And today, it's invited a very special guest.","TWN":"我們今天就請到一位特別來賓。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"태스크포스, <color=#ffd34c>조디악 나이츠</color>. 피오네 로웰 부단장님이십니다.","JPN":"タスクフォース、<color=#ffd34c>ゾディアックナイツ</color>。フィオネ・ローウェル副団長です。","ENG":"It's Deputy Fione Rowell of the <color=#ffd34c>Zodiac Knights</color> TASKFORCE.","TWN":"就是特遣勢力 <color=#ffd34c>十二宮騎士團</color>的菲奧尼副團長。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"모두 박수로 맞아주시길.","JPN":"拍手でお迎えください。","ENG":"Let's welcome her with a round of applause!","TWN":"掌聲歡迎她～"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"……조디악 나이츠?","JPN":"……ゾディアックナイツ？","ENG":"...The Zodiac Knights?","TWN":"……十二宮騎士團？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"기사 코스프레로 유명한 태스크포스 아니야?","JPN":"騎士のコスプレで有名なタスクフォースじゃないか？","ENG":"The TASKFORCE known for its knight costumes?","TWN":"不就是那個Cosplay騎士很出名的特遣勢力嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"맞아, 맞아. 그 민중을 지키는 기사단!","JPN":"そうそう、あの民衆を守る騎士団！","ENG":"Yes, yes. The knights who serve the public!","TWN":"對啊對啊。就是那個守護民眾的騎士團！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"……푸핫, 민중을 지킨다니. 그게 뭐야? 무슨 촌스러운 옛날 만화도 아니고.","JPN":"……ぷはっ！　民衆を守るとかダサすぎる。昔の漫画じゃあるまいし。","ENG":"...Pssh! Serve the public. What does that mean? Sounds like some old, corny cartoon catchphrase.","TWN":"……噗哈哈，還守護民眾咧？什麼鬼？又不是很久以前的漫畫！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"안녕하십니까, 아카데미 학생 여러분.","JPN":"おはようございます、アカデミー生徒の皆さん。","ENG":"Good morning, students of the Academy.","TWN":"學院的同學們，大家好。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠의 부단장 직위를 맏고 있는 피오네 로웰이라고 합니다.","JPN":"ゾディアックナイツの副団長を勤めています、フィオネ・ローウェルと申します。","ENG":"My name is Fione Lowell, and I'm the deputy captain of the Zodiac Knights.","TWN":"我是十二宮騎士團的副團長，菲奧尼。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아카데미 학생 여러분의 명성은 익히 들어 잘 알고 있습니다.","JPN":"アカデミーの皆さんの素晴らしさについては、私もよく話を聞いています。","ENG":"I've heard many great things about you and your school.","TWN":"久仰各位同學的大名。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오늘 하루, 여러분의 일일 교관으로 초청 받아 무척 기쁘게 생각하고 있습니다.","JPN":"今日は皆さんの1日教官としてお招きいただき、とても嬉しく思っています。","ENG":"I'm honored to be here as your instructor for the day.","TWN":"非常開心能夠受邀擔任各位同學的一日教官。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 모쪼록…….","JPN":"本日は何卒……","ENG":"And hopefully...","TWN":"那就請多……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야? 기사 흉내나 내는 관종 집단이 누굴 가르친다는 거야?","JPN":"は？　騎士気取りの集団のくせに私たちを指導するとか、図々しいんじゃない？","ENG":"What? No, I've got nothing to learn from some pseudo knight group.","TWN":"什麼嘛？不過就是靠模仿騎士賺讚數的組織，竟然說要當我們的教官？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘! 말이 너무 심하잖아!","JPN":"ナイエル！　さすがにそれは言い過ぎだよ！","ENG":"Naielle! That's not nice!","TWN":"奈爾！你這樣說太過分了！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥! 학생회에서도 예산을 너무 쪼잔하게 쓰는 거 아니야?","JPN":"ふんっ！　生徒会も予算ケチりすぎよ。","ENG":"Geez, is the Student Council budget so low?","TWN":"哼！學生會也太節省預算了吧？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"얼마나 초청할 사람이 없었으면, 저런 촌스러운 냄새 풍기는 구닥다리를 초대한 거냐구.","JPN":"いくら人材がいないからって、あんなダサい人を呼ぶなんてありえない。","ENG":"Of all the people they could have invited, they invited that—an old, unsophisticated-looking country woman.","TWN":"是沒人可以邀請了嗎？竟然請到這種土裡土氣的傢伙！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"적어도 이 나이엘 님이 보고 감탄할 만큼 대단한 사람을 모셔 와야지.","JPN":"せめてこのナイエル様が尊敬できるようなすごい人を呼んでちょうだいよね。","ENG":"Why can't they bring in someone who can impress me?","TWN":"起碼也邀請個讓我看一眼就能發出讚嘆的人物吧！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐, 애초에 그런 사람이 얼마나 있겠냐만은.","JPN":"まあ、そんな人そうそういないでしょうけど。","ENG":"But then again, it's an impossible task to accomplish.","TWN":"雖然這種人是不多啦！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘, 네가 몰라서 그렇지 사실, 조디악 나이츠는…….","JPN":"ナイエルが知らないだけで、実はゾディアックナイツって……","ENG":"Naielle, you don't know what you're talking about. The Zodiac Knights—","TWN":"奈爾，應該是你孤陋寡聞，其實十二宮騎士團……"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};